const sword = findItem('sword');
const chestplate = findItem('chestplate') || findItem('tunic');
if (chestplate) await bot.equip(chestplate, 'chest');
if (sword) await bot.equip(sword, 'hand');
const getHostiles = () => {
  return Object.values(bot.entities).filter(e => {
    if (e.type !== 'mob') return false;
    const name = e.name?.toLowerCase() || '';
    const isHostile = name.includes('zombie') || name.includes('skeleton') || name.includes('creeper') || name.includes('spider') || name.includes('husk') || name.includes('drowned');
    return isHostile && e.position.distanceTo(bot.entity.position) < args.scanRadius;
  }).sort((a, b) => a.position.distanceTo(bot.entity.position) - b.position.distanceTo(bot.entity.position));
};
startBackgroundSkill(bot, 'coordinate_defense', async (token) => {
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  while (!token.cancelled && bot.health > 0 && bot.entity) {
    if (!bot.physicsEnabled) {
      await new Promise(r => setTimeout(r, 100));
      continue;
    }
    const hostiles = getHostiles();
    const nearest = hostiles[0];
    const partner = Object.values(bot.players).find(p => p.username === args.partnerName)?.entity;
    if (nearest) {
      const hostPos = nearest.position;
      const botPos = bot.entity.position;
      const distance = botPos.distanceTo(hostPos);
      if (distance < args.attackRange) {
        bot.lookAt(hostPos);
        bot.attack(nearest);
      }
      if (distance < args.preferredDistance) {
        const retreatDir = botPos.minus(hostPos).normalize();
        const retreatTarget = hostPos.plus(retreatDir.scale(args.preferredDistance + 2));
        bot.pathfinder.setGoal(new goals.GoalNear(retreatTarget.x, retreatTarget.y, retreatTarget.z, 1));
      } else if (partner) {
        bot.pathfinder.setGoal(new goals.GoalFollow(partner, 4));
      } else {
        bot.pathfinder.setGoal(null);
      }
    } else if (partner) {
      const distToPartner = bot.entity.position.distanceTo(partner.position);
      if (distToPartner > 5) {
        bot.pathfinder.setGoal(new goals.GoalFollow(partner, 3));
      } else {
        bot.pathfinder.setGoal(null);
      }
    } else {
      bot.pathfinder.setGoal(null);
    }
    await new Promise(r => setTimeout(r, 400));
  }
});
return "<DEFENDING>: Coordinating defense with " + args.partnerName + ". Maintaining " + args.preferredDistance + "m distance from threats.";"
}

