  "code": "const sleep = function (ms) { return new Promise(function (resolve) { setTimeout(resolve, ms); }); };
const normalize = function (name) { return name.toLowerCase().replace(/_/g, ' ').trim(); };
const requestedName = normalize(args.itemName);
const findFood = function () {
  return bot.inventory.items().find(function (item) {
    return normalize(item.name).includes(requestedName) || normalize(item.displayName).includes(requestedName);
  });
};
const firstFood = findFood();
if (!firstFood) {
  return "<NO_ITEM>: Could not find any food matching '" + args.itemName + "' in inventory.";
}
const isAlwaysEdible = ['golden_apple', 'enchanted_golden_apple', 'chorus_fruit'].some(function (name) { return firstFood.name.includes(name); });
if ((bot.food || 0) >= 20 && !isAlwaysEdible) {
  return "<ALREADY_FULL>: Hunger is already full; cannot eat " + firstFood.displayName + ".";
}
startBackgroundSkill(bot, 'eat_food', async function (token) {
  let eaten = 0;
  const pollMs = 50;
  const consumeDuration = 1700;
  const canContinue = function () {
    return !token.cancelled && bot.health > 0 && Boolean(bot.entity);
  };
  while (canContinue() && eaten < args.count) {
    const food = findFood();
    if (!food) { break; }
    if ((bot.food || 0) >= 20 && !isAlwaysEdible) { break; }
    await bot.equip(food, 'hand');
    while (!bot.physicsEnabled) {
      if (!canContinue()) { return; }
      await sleep(pollMs);
    }
    try {
      bot.activateItem();
      await sleep(consumeDuration);
      bot.deactivateItem();
      eaten++;
    } catch (err) {
      if (!token.cancelled) { console.error('Error during eating:', err); }
      break;
    }
    if (canContinue()) { await sleep(200); }
  }
  if (!token.cancelled) {
    console.log('Finished eating ' + eaten + ' ' + args.itemName + '(s). Current food: ' + bot.food);
  }
});
return "<EATING>: Attempting to eat " + args.count + " " + firstFood.displayName + "(s).";"
}
